#nullable enable // autogenerated

using MVZ2.Vanilla.Enemies;
using MVZ2.Vanilla.Entities;

using PVZEngine.Definitions;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Enemies
{
    [AutoEntityBehaviourDefinition(VanillaEntityBehaviourNames.spider_State)]
    public class Spider_StateBehaviour : EnemyStateBehaviour
    {
        public Spider_StateBehaviour(string nsp, string name) : base(nsp, name)
        {
        }
        protected override int GetActiveState(Entity enemy)
        {
            if (Spider.IsClimbingVertically(enemy))
            {
                return STATE_CLIMB;
            }
            return base.GetActiveState(enemy);
        }
        public const int STATE_CLIMB = VanillaEnemyStates.SPIDER_CLIMB;
    }
}
